def myAtoi(s):
    s=s.lstrip();
    if not s: return 0
    sn=1
    if s[0]=='-': sn=-1; s=s[1:]
    elif s[0]=='+': s=s[1:]
    res=0
    for c in s:
        if not c.isdigit(): break
        res=res*10+int(c)
    res*=sn
    return max(-2**31, min(2**31-1, res))

